const topic = $.input.researchTopic;
const staticTerms = 'research report analysis trends 2025';
return { query: topic + ' ' + staticTerms };

const results = $.steps.primarySearch.response.results || [];
const sources = results.map((r, i) => ({
  index: i + 1,
  title: r.title || 'Untitled',
  url: r.url || '',
  text: (r.text || '').slice(0, 1500)
})).filter(s => s.url.length > 0).slice(0, 5);
return { sources, count: sources.length };

const sources = $.steps.extractSources.output.sources || [];
const iterations = $.steps.deepScrape.response.iterations || [];
let compiled = '';
sources.forEach((s, i) => {
  compiled += '--- SOURCE ' + s.index + ': ' + s.title + ' ---\n';
  compiled += 'URL: ' + s.url + '\n';
  if (iterations[i] && iterations[i].scrapeOne && iterations[i].scrapeOne.response) {
    const sc = iterations[i].scrapeOne.response;
    const content = sc.data ? (sc.data.markdown || sc.data.content || sc.data.text || '') : (typeof sc === 'string' ? sc : JSON.stringify(sc));
    compiled += content.slice(0, 4000) + '\n';
  } else {
    compiled += s.text + '\n';
  }
  compiled += '\n';
});
return { compiled: compiled.slice(0, 30000), sourceCount: sources.length };

const d = $.steps.compileResearch.output;
const topic = $.input.researchTopic;
const audience = $.input.targetAudience;
const title = $.input.reportTitle;
let prompt = 'You are a senior research analyst creating a high-value lead magnet report.\n\n';
prompt += 'TOPIC: ' + topic + '\n';
prompt += 'TARGET AUDIENCE: ' + audience + '\n';
prompt += 'REPORT TITLE: ' + title + '\n\n';
prompt += 'RESEARCH DATA (' + d.sourceCount + ' sources):\n';
prompt += d.compiled + '\n';
prompt += 'INSTRUCTIONS:\n';
prompt += '- Create a comprehensive, professionally structured report\n';
prompt += '- Include executive summary, key findings, data points, actionable insights\n';
prompt += '- Make it valuable enough to serve as a lead magnet\n';
prompt += '- Include sources and citations\n';
prompt += '- Target length: 1500-2500 words\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "title": "report title",\n';
prompt += '  "executiveSummary": "3-4 sentence executive summary",\n';
prompt += '  "sections": [{\n';
prompt += '    "heading": "section title",\n';
prompt += '    "content": "section content"\n';
prompt += '  }],\n';
prompt += '  "keyFindings": ["finding1", "finding2"],\n';
prompt += '  "actionableInsights": ["insight1", "insight2"],\n';
prompt += '  "sources": ["source1", "source2"],\n';
prompt += '  "wordCount": 0\n';
prompt += '}';
return { prompt };

let raw = $.steps.aiGenerate.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { title: $.input.reportTitle, executiveSummary: raw.slice(0, 300), sections: [{ heading: 'Report', content: raw }], keyFindings: [], actionableInsights: [], sources: [], wordCount: 0 }; }

const ai = $.steps.parseAI.output;
const docResp = $.steps.createDoc.response || {};
const documentId = docResp.documentId || '';

let text = '';
text += (ai.title || 'Research Report') + '\n\n';
text += 'EXECUTIVE SUMMARY\n';
text += (ai.executiveSummary || '') + '\n\n';
(ai.sections || []).forEach(s => {
  text += (s.heading || '').toUpperCase() + '\n';
  text += (s.content || '') + '\n\n';
});
if (ai.keyFindings && ai.keyFindings.length > 0) {
  text += 'KEY FINDINGS\n';
  ai.keyFindings.forEach((f, i) => { text += (i + 1) + '. ' + f + '\n'; });
  text += '\n';
}
if (ai.actionableInsights && ai.actionableInsights.length > 0) {
  text += 'ACTIONABLE INSIGHTS\n';
  ai.actionableInsights.forEach((ins, i) => { text += (i + 1) + '. ' + ins + '\n'; });
  text += '\n';
}
if (ai.sources && ai.sources.length > 0) {
  text += 'SOURCES\n';
  ai.sources.forEach((s, i) => { text += (i + 1) + '. ' + s + '\n'; });
}

return { documentId, text: text.slice(0, 45000) };

const ai = $.steps.parseAI.output;
const docId = $.steps.buildDocContent.output.documentId;

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'Research Report Ready', emoji: true } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*' + (ai.title || 'Report') + '*' } });

if (ai.executiveSummary) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: ai.executiveSummary.slice(0, 500) } });
}

if (ai.keyFindings && ai.keyFindings.length > 0) {
  const findings = ai.keyFindings.slice(0, 3).map((f, i) => (i + 1) + '. ' + f).join('\n');
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Key Findings:*\n' + findings } });
}

if (docId) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '<https://docs.google.com/document/d/' + docId + '/edit|Open in Google Docs>' } });
}

blocks.push({ type: 'divider' });
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Powered by Exa + Firecrawl + Claude AI + Google Docs' }] });

const fallback = 'Research Report: ' + (ai.title || 'Report') + ' - ready in Google Docs';
return { blocks, fallback };
